import sys; sys.path.insert(0,'src')
from jinja2 import Environment
from jinja2.ext import i18n

env = Environment(extensions=[i18n])

class Translations:
    def gettext(self, s):
        return 'GETTEXT:' + s
    def ngettext(self, s, p, n):
        return 'NGETTEXT:' + (s if n==1 else p)
    def dgettext(self, d, s):
        return f'D[{d}]:' + s
    def dngettext(self, d, s, p, n):
        return f'DN[{d}]:' + (s if n==1 else p)

env.install_gettext_translations(Translations())

tmpl = env.from_string('{% trans domain=\"admin\" %}Hello{% endtrans %}')
print(tmpl.render())

tmpl2 = env.from_string('{% trans domain=\"admin\", count=3 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(tmpl2.render())

tmpl3 = env.from_string('{% trans %}Hi{% endtrans %}')
print(tmpl3.render())
"
